{"command":"cd /data/btguan/auto-opt/utils/llvm-122235 && cat << 'EOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp 2231 2246
    // Left or right might be masked.
    if (SimplifyDemandedInstructionBits(*II))
      return &CI;

    // The shift amount (operand 2) of a funnel shift is modulo the bitwidth,
    // so only the low bits of the shift amount are demanded if the bitwidth is
    // a power-of-2.
    if (!isPowerOf2_32(BitWidth))
      break;
    APInt Op2Demanded = APInt::getLowBitsSet(BitWidth, Log2_32_Ceil(BitWidth));
    KnownBits Op2Known(BitWidth);
    if (SimplifyDemandedBits(II, 2, Op2Demanded, Op2Known))
      return &CI;

    // fshl(X, 0, Y) --> shl X, Y if Y < BitWidth
    // fshl(X, undef, Y) --> shl X, Y if Y < BitWidth
    if (IID == Intrinsic::fshl && (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))) {
      if (Op2Known.getMaxValue().ult(BitWidth))
        return BinaryOperator::CreateShl(Op0, II->getArgOperand(2));
    }

    // fshr(0, X, Y) --> lshr X, Y if Y < BitWidth
    // fshr(undef, X, Y) --> lshr X, Y if Y < BitWidth
    if (IID == Intrinsic::fshr && (match(Op0, m_ZeroInt()) || match(Op0, m_Undef()))) {
      if (Op2Known.getMaxValue().ult(BitWidth))
        return BinaryOperator::CreateLShr(Op1, II->getArgOperand(2));
    }

    break;
  }
EOF"}

